(function() {
  // パラメータ検出用: post_library_id={{post_library_id}}
  // メイン投稿のコンテナを特定して、その中だけからメディアURLを取得
  const mainContent = document.querySelector('[aria-label="列の本文"]');
  if (!mainContent) {
    return { didAction: false, reason: 'Main content area not found' };
  }

  // 最初の data-pressable-container を見つける（メイン投稿）
  const mainPostContainer = mainContent.querySelector('div[data-pressable-container="true"]');
  if (!mainPostContainer) {
    return { didAction: false, reason: 'Main post container not found' };
  }

  // メイン投稿コンテナに一時的なIDを付与して、セレクタで特定できるようにする
  // （メディアが無い場合でもIDを付与して、save_mediaステップで空の結果を返せるようにする）
  const tempId = 'main-post-container-' + Date.now();
  mainPostContainer.setAttribute('data-main-post-id', tempId);

  return {
    didAction: true,
    containerId: tempId
  };
})()
